                const uint32_t curOut = (bo + tileOut_ <= outLen_) ? tileOut_ : (outLen_ - bo);
                const uint32_t chunkLen = (curOut - 1u) * stride_ + ksize_;

                CopyIn(gmRowInBase, bo, curOut, chunkLen);
                Compute(curOut, chunkLen);
                CopyOut(gmRowOutBase, bo, curOut);
            }
        }
